        applyStateEffect(true);
      }
    } else {
      if (modal) {
        detachBodyProperty();
        applyStateEffect(false);
      }
    }

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
      if (modal) {
        detachBodyProperty();
        applyStateEffect(false);
      }
    };
  }, [render, modal, scrollbarWidth]);

  return [hasScrollbar, scrollbarWidth] as const;
}

